class ContextManager:
    def __init__(self):
        self.context = {}

    def update_context(self, key, value):
        self.context[key] = value

    def get_context(self, key):
        return self.context.get(key)

    def clear_context(self):
        self.context.clear()




class PositionalNGramCalculator:
    @lru_cache(maxsize=1000)
    def calculate_positional_ngram_frequencies(self, text, n=2, tolerance=1):
        """
        计算文本中每个n-gram在不同位置的频率，考虑位置容差。
        """
        frequencies = defaultdict(int)
        ngram_positions = defaultdict(list)

        text_length = len(text)
        max_index = text_length - n + 1

        # 记录每个n-gram出现的位置
        for i in range(max_index):
            ngram = text[i:i+n]
            ngram_positions[ngram].append(i)
            frequencies[ngram] += 1

        position_based_frequencies = defaultdict(int)

        # 计算基于位置的频率
        for ngram, positions in ngram_positions.items():
            for pos in positions:
                # 预计算调整位置，避免重复计算范围
                for delta in range(-tolerance, tolerance + 1):
                    adjusted_pos = pos + delta
                    if 0 <= adjusted_pos < max_index:
                        position_key = (ngram, adjusted_pos)
                        position_based_frequencies[position_key] += 1

        return position_based_frequencies

class FrequencyCalculator:
    def __init__(self):
        # 将term_weights转换为字典，并存储为实例变量
        self.term_weights_dict = {
            "健康": 2, "运动": 2, "饮食": 2, "睡眠": 2, "工作": 2, "学习": 2, "旅行": 2,
            "电影": 2, "音乐": 2, "阅读": 2, "烹饪": 2, "购物": 2, "散步": 2, "跑步": 2,
            "瑜伽": 2, "健身": 2, "游泳": 2, "自行车": 2, "咖啡": 2, "茶": 2, "水": 2,
            "早餐": 2, "午餐": 2, "晚餐": 2, "水果": 2, "蔬菜": 2, "蛋白质": 2, '语音': 2,
            "碳水化合物": 2, "脂肪": 2, "幸福": 2, "快乐": 2, "压力": 2, "朋友": 2,
            "家人": 2, "宠物": 2, "天气": 2, "环境": 2, "教育": 2, "科技": 2, "艺术": 2,
            "文化": 2, "经济": 2, "政治": 2, "社会": 2, "男朋友": 2, "女朋友": 2
        }

    @lru_cache(maxsize=500)
    def calculate_weighted_character_frequencies(self, text):
        """
        计算文本中每个字符的加权频率，权重基于term_weights_dict。
        """
        frequencies = defaultdict(float)
        for char in text:
            # 如果字符是术语的一部分，使用其权重；否则，默认权重为1.0
            weight = self.term_weights_dict.get(char, 1.0)
            frequencies[char] += weight
        return dict(frequencies)

class SimilarityCalculator:
    def __init__(self):
        self.freq_calculator = FrequencyCalculator()
        self.ngram_calculator = PositionalNGramCalculator()
        self.term_weights = [
            ("健康", 2), ("运动", 2), ("饮食", 2), ("睡眠", 2), ("工作", 2), ("学习", 2), ("旅行", 2),
            ("电影", 2), ("音乐", 2), ("阅读", 2), ("烹饪", 2), ("购物", 2), ("散步", 2), ("跑步", 2),
            ("瑜伽", 2), ("健身", 2), ("游泳", 2), ("自行车", 2), ("咖啡", 2), ("茶", 2), ("水", 2),
            ("早餐", 2), ("午餐", 2), ("晚餐", 2), ("水果", 2), ("蔬菜", 2), ("蛋白质", 2), ('语音', 2),
            ("碳水化合物", 2), ("脂肪", 2), ("幸福", 2), ("快乐", 2), ("压力", 2), ("朋友", 2),
            ("家人", 2), ("宠物", 2), ("天气", 2), ("环境", 2), ("教育", 2), ("科技", 2), ("艺术", 2),
            ("文化", 2), ("经济", 2), ("政治", 2), ("社会", 2), ("男朋友", 2), ("女朋友", 2)
        ]
        self.mode = "平衡"
        self.thresholds = {
            "严谨": 0.8,
            "精准": 0.8,
            "平衡": 0.56,
            "创造": 0.36
        }

    def set_mode(self, mode):
        """
        设置相似度计算模式。
        """
        if mode in self.thresholds:
            self.mode = mode
            return f"已切换到{mode}模式，当前相似度阈值为{self.thresholds[mode]}"
        return "无效的模式，请选择：严谨、精准、平衡或创造模式"

    def get_threshold(self):
        """
        获取当前模式下的相似度阈值。
        """
        return self.thresholds[self.mode]

    @lru_cache(maxsize=1000)
    def compare_positional_ngram_frequency_similarity(self, text1, text2, n=2, tolerance=1):
        """
        基于位置的n-gram频率相似度比较。
        """
        freqs1 = self.ngram_calculator.calculate_positional_ngram_frequencies(text1, n, tolerance)
        freqs2 = self.ngram_calculator.calculate_positional_ngram_frequencies(text2, n, tolerance)
        keys = set(freqs1.keys()) | set(freqs2.keys())
        weighted_intersection = sum(min(freqs1.get(key, 0), freqs2.get(key, 0)) for key in keys)
        weighted_union = sum(max(freqs1.get(key, 0), freqs2.get(key, 0)) for key in keys)
        return weighted_intersection / weighted_union if weighted_union > 0 else 0

    @lru_cache(maxsize=1000)
    def compare_weighted_jaccard_similarity(self, text1, text2):
        """
        计算加权Jaccard相似度。
        """
        weighted_freq_sim = self.compare_weighted_frequency_similarity_with_terms(text1, text2)
        jaccard_sim = self.compare_simple_intersection_similarity(text1, text2)
        combined_sim = (weighted_freq_sim + jaccard_sim) / 2
        return combined_sim

    @lru_cache(maxsize=1000)
    def compare_weighted_frequency_similarity_with_terms(self, text1, text2):
        """
        基于加权字符频率的相似度比较。
        """
        if not text1 or not text2:
            return 0

        # 分别计算text1和text2的加权频率
        freqs1 = self.freq_calculator.calculate_weighted_character_frequencies(text1)
        freqs2 = self.freq_calculator.calculate_weighted_character_frequencies(text2)

        # 计算加权交集和并集
        intersection = sum(min(freqs1.get(char, 0), freqs2.get(char, 0)) for char in freqs1 if char in freqs2)
        union = sum(max(freqs1.get(char, 0), freqs2.get(char, 0)) for char in set(freqs1) | set(freqs2))
        return intersection / union if union > 0 else 0

    @lru_cache(maxsize=1000)
    def compare_simple_intersection_similarity(self, text1, text2):
        """
        计算简单的交集相似度。
        """
        if not text1 or not text2:
            return 0
        set1 = set(text1)
        set2 = set(text2)
        intersection_size = len(set1 & set2)
        union_size = max(len(set1), len(set2))
        return intersection_size / union_size if union_size > 0 else 0

    def _find_match_with_method(self, input_text, corpus, similarity_method, threshold):
        """
        使用指定的相似度方法在语料库中查找匹配。
        """
        highest_similarity = 0
        closest_match_group = None

        for question_group in corpus.keys():
            for question in question_group:
                similarity = similarity_method(input_text, question)
                if similarity > threshold and similarity > highest_similarity:
                    highest_similarity = similarity
                    closest_match_group = question_group

        return highest_similarity, closest_match_group

    def _find_match_with_average_similarity(self, input_text, corpus, threshold):
        """
        使用平均相似度在语料库中查找匹配。
        """
        highest_avg_similarity = 0
        closest_match_group = None

        for question_group in corpus.keys():
            for question in question_group:
                ngram_sim = self.compare_positional_ngram_frequency_similarity(input_text, question)
                weighted_sim = self.compare_weighted_jaccard_similarity(input_text, question)
                simple_sim = self.compare_simple_intersection_similarity(input_text, question)
                avg_similarity = (ngram_sim + weighted_sim + simple_sim) / 3
                if avg_similarity > threshold and avg_similarity > highest_avg_similarity:
                    highest_avg_similarity = avg_similarity
                    closest_match_group = question_group

        return highest_avg_similarity, closest_match_group

    def find_closest_match(self, input_text, corpus):
        """
        查找与输入文本最接近的匹配。
        """
        threshold = self.get_threshold()

        # 按相似度方法的优先级查找匹配
        similarity_methods = [
            self.compare_positional_ngram_frequency_similarity,
            self.compare_weighted_jaccard_similarity,
            self._find_match_with_average_similarity,  # 需要特殊处理
            self.compare_simple_intersection_similarity
        ]

        # 首先尝试使用前两个方法
        for method in similarity_methods[:2]:
            highest_similarity, closest_match_group = self._find_match_with_method(
                input_text, corpus, method, threshold
            )
            if closest_match_group:
                return closest_match_group, highest_similarity

        # 使用平均相似度方法
        highest_similarity, closest_match_group = self._find_match_with_average_similarity(
            input_text, corpus, threshold
        )
        if closest_match_group:
            return closest_match_group, highest_similarity

        # 最后尝试使用简单交集相似度
        highest_similarity, closest_match_group = self._find_match_with_method(
            input_text, corpus, self.compare_simple_intersection_similarity, threshold
        )
        if closest_match_group:
            return closest_match_group, highest_similarity

        return None, 0



class IdiomExplainer:
    def __init__(self, idioms, context_manager):
        self.idioms = idioms
        self.context_manager = context_manager

    def explain(self, input_text):
        if len(input_text) > 20:
            return None

        found_idioms = []
        for idiom in self.idioms:
            if idiom in input_text:
                found_idioms.append(f"{idiom}的意思是：{self.idioms[idiom]}")
                self.context_manager.update_context('last_function', 'idiom')
                self.context_manager.update_context('last_idiom', idiom)

        if found_idioms:
            return '\n'.join(found_idioms)
        return None


