class InformationCompleter:
    def __init__(self, context_manager, tokenizer):
        self.context_manager = context_manager
        self.tokenizer = tokenizer
        self.max_history = 5
        self.conversation_history = []
        self.question_words = set(["多少", "什么", "哪些", "如何", "怎么", "为什么", "吗", "么", "哪", "几"])
        self.last_extracted_noun = None

    def add_to_history(self, text):
        """将用户输入添加到历史记录中，并提取最后一个名词。"""
        self.conversation_history.append(text)
        if len(self.conversation_history) > self.max_history:
            self.conversation_history.pop(0)
        
        current_noun = self._extract_last_noun(text)
        if current_noun:
            self.last_extracted_noun = current_noun

    def complete_information(self, current_input):
        """根据历史记录补全当前输入，但不补全包含数字的输入。"""
        if not self.conversation_history:
            return current_input

        # 如果当前输入包含数字，则不进行补全
        if self._contains_number(current_input):
            return current_input

        last_input = self.conversation_history[-1]

        # 如果当前输入包含疑问词，尝试基于上一个名词进行补全
        if self._contains_question_word(current_input):
            # 检查是否已经包含上一个名词
            last_noun = self.last_extracted_noun or self._extract_last_noun(last_input)
            if last_noun and last_noun not in current_input:
                # 确保补全的名词不包含数字
                if not self._contains_number(last_noun):
                    # 这里根据具体的句型进行补全，可以根据需要调整
                    # 例如，对于“属于什么违法？”补全为“属于外卖什么违法？”
                    return f"{last_noun}{current_input}"
        
        # 特定句型补全：处理“有...吗”结构
        if "有" in last_input and (current_input.endswith("有") or current_input.endswith("没有")):
            key_info = self._extract_key_info(last_input)
            if key_info and not self._contains_number(key_info) and key_info not in current_input:
                completed_input = f"{current_input}{key_info}"
                return self._remove_question_particles(completed_input)
        
        # 处理“什么”或“哪个”相关的问题
        if "什么" in current_input or "哪个" in current_input:
            repeated_word = self._find_repeated_word(last_input, current_input)
            if repeated_word and not self._contains_number(repeated_word) and repeated_word not in current_input:
                key_info = self._extract_key_info(last_input)
                if key_info:
                    return f"{key_info}{current_input}"
        
        # 处理简短且非疑问句的输入
        if len(current_input) <= 5 and not self._is_question(current_input):
            key_words = self._extract_key_words(last_input)
            for word in key_words:
                if word not in current_input and not self._contains_number(word):
                    return f"{word}{current_input}"
        
        return current_input

    def _contains_question_word(self, text):
        """检查文本是否包含疑问词。"""
        return any(word in text for word in self.question_words)

    def _extract_last_noun(self, text):
        """提取文本中的最后一个名词。"""
        tokens = self.tokenizer.tokenize(text)
        nouns = [token for token, pos in tokens if '名词' in pos]
        return nouns[-1] if nouns else None

    def _remove_question_particles(self, text):
        """移除疑问句末尾的疑问助词。"""
        particles = ["吗", "呢", "啊", "哦"]
        for particle in particles:
            if text.endswith(particle):
                return text[:-1]
        return text

    def _find_repeated_word(self, text1, text2):
        """查找 text1 中的重复词语是否出现在 text2 中。"""
        # 改进：查找最长的重复词语
        for length in range(3, 0, -1):  # 尝试长度为3, 2, 1
            for i in range(len(text1) - length + 1):
                word = text1[i:i+length]
                if word in text2 and not self._contains_number(word):
                    return word
        return None

    def _is_question(self, text):
        """判断文本是否为疑问句。"""
        return self._contains_question_word(text)

    def _extract_key_info(self, text):
        """从句子中提取关键信息，避免包含数字。"""
        # 这里假设关键信息在“有”之后，且不包含“吗”
        match = re.search(r'有(.+?)吗', text)
        if match:
            key_info = match.group(1).strip()
            if not self._contains_number(key_info):
                return key_info
        return None

    def _contains_number(self, text):
        """检查文本中是否包含数字。"""
        return bool(re.search(r'\d', text))

    def _extract_key_words(self, text):
        """从文本中提取关键字，排除疑问词和包含数字的词。"""
        # 使用正则表达式提取连续的两个字符作为关键词
        words = [text[i:i+2] for i in range(len(text)-1)]
        return [word for word in words if len(word) == 2 and not self._is_question(word) and not self._contains_number(word)]



