class AstrologySystem:
    def __init__(self):
        self.context_manager = ContextManager()
        self.constellation_finder = ConstellationFinder()
        self.zodiac_calculator = ZodiacCalculator()

    def process_input(self, user_input):
        # 提取日期信息
        date_match = re.search(r'(\d{2,4})年?(\d{1,2})[月\-\.](\d{1,2})[日号]?', user_input)
        if date_match:
            year, month, day = map(int, date_match.groups())
            self.context_manager.update_context('year', year)
            self.context_manager.update_context('month', month)
            self.context_manager.update_context('day', day)

        # 判断查询类型
        if '星座' in user_input or ('生日' in user_input and '生肖' not in user_input):
            return self.get_constellation()
        elif '生肖' in user_input or '属相' in user_input:
            return self.get_zodiac()
        else:
            return "请问你想知道星座还是生肖呢？"

    def get_constellation(self):
        month = self.context_manager.get_context('month')
        day = self.context_manager.get_context('day')
        if month and day:
            try:
                datetime(2000, month, day)  # 验证日期有效性
                constellation = self.constellation_finder.find_constellation(month, day)
                if constellation:
                    return f"你的星座是{constellation}"
                else:
                    return "无法确定星座，请检查输入的日期是否正确。"
            except ValueError:
                return "请输入有效的日期。"
        else:
            return "请提供完整的出生日期（月和日）以确定星座。"

    def get_zodiac(self):
        year = self.context_manager.get_context('year')
        if year:
            animal, info = self.zodiac_calculator.calculate_zodiac(year)
            return f"你的生肖是{animal}，{info}"
        else:
            return "请提供出生年份以确定生肖。"




class ChengyuJielongGame:
    def __init__(self, idioms, pinyin_dict):
        self.idioms = set(idioms)  # 使用集合提高查找效率
        self.pinyin_dict = pinyin_dict
        self.game_active = False
        self.robot_chance_used = False
        self.current_idiom = None
        self.used_idioms = set()  # 记录已使用的成语，防止重复

    def get_pinyin(self, char):
        for pinyin, chars in self.pinyin_dict.items():
            if any(c[:-1] == char for c in chars):  # 忽略声调数字
                return pinyin
        return None

    def find_next_idiom(self, last_char):
        # 优先字符匹配
        matching_idioms = [idiom for idiom in self.idioms if idiom.startswith(last_char) and idiom not in self.used_idioms]
        if matching_idioms:
            return random.choice(matching_idioms)
        
        # 拼音匹配
        last_char_pinyin = self.get_pinyin(last_char)
        if last_char_pinyin:
            candidates = [c[:-1] for c in self.pinyin_dict.get(last_char_pinyin, [])]  # 忽略声调数字
            matching_idioms = [idiom for idiom in self.idioms if idiom[0] in candidates and idiom not in self.used_idioms]
            if matching_idioms:
                return random.choice(matching_idioms)
        
        return None

    def is_valid_idiom(self, idiom):
        # 检查成语的长度是否为 4、6 或 8
        if len(idiom) not in [4, 6, 8]:
            return False
        # 检查成语是否仅由汉字组成
        if not all('\u4e00' <= char <= '\u9fff' for char in idiom):
            return False
        # 检查成语是否有三个及以上相同的字符
        if any(idiom.count(char) >= 3 for char in set(idiom)):
            return False
        # 检查成语是否已经被使用过
        if idiom in self.used_idioms:
            return False
        return True

    def process_user_idiom(self, user_input):
        response = ""
        self.used_idioms.add(user_input)
        self.current_idiom = user_input
        next_idiom = self.find_next_idiom(user_input[-1])
        
        if next_idiom:
            self.used_idioms.add(next_idiom)
            self.current_idiom = next_idiom
            response += f"{next_idiom}"
            return response, self.current_idiom
        else:
            # 如果找不到匹配的成语，尝试解释为什么找不到
            last_char = user_input[-1]
            last_char_pinyin = self.get_pinyin(last_char)
            if last_char_pinyin:
                response += "你好厉害，我输了。"
            else:
                response += "我找不到可以接的成语了，我输了。"
            self.game_active = False
            return response, None

    def start_game(self):
        self.game_active = True
        self.robot_chance_used = False
        self.used_idioms.clear()
        self.current_idiom = None
        
        first_turn = random.choice(["user", "robot"])
        start_dialogues = [
            "成语接龙开始了！",
            "我们来玩成语接龙吧!",
            "成语接龙游戏开始！",
            "让我们开始成语接龙游戏吧！",
        ]
        
        if first_turn == "robot":
            self.current_idiom = random.choice(list(self.idioms))
            self.used_idioms.add(self.current_idiom)
            return f"{random.choice(start_dialogues)} 我先来：{self.current_idiom}"
        else:
            user_turn_dialogues = [
                " 请你先开始说出成语吧！",
                " 你先来吧，说一个成语。",
                " 你先说一个成语。",
            ]
            return f"{random.choice(start_dialogues)}{random.choice(user_turn_dialogues)}"

    def handle_user_doesnt_know(self):
        # 提供一个提示
        if self.current_idiom:
            last_char = self.current_idiom[-1]
            hint_idiom = self.find_next_idiom(last_char)
            if hint_idiom:
                self.used_idioms.add(hint_idiom)  # 确保提示的成语也被记录为使用过
                self.current_idiom = hint_idiom
                return f"提示一个成语：{hint_idiom}", self.current_idiom
        return "这个需要你自己想哦，如果想不出来只能认输喽。", self.current_idiom

    def process_user_input(self, user_input):
        exit_commands = ["不玩了", "不想玩了", "结束", "退出", "拜拜", "再见"]
        hint_commands = ["提示", "我不知道", "帮助", "提示一下", "不会"]

        if user_input in exit_commands:
            self.game_active = False
            return "成语接龙游戏结束了，下次再玩吧！", None

        if user_input in hint_commands:
            return self.handle_user_doesnt_know()

        if not self.is_valid_idiom(user_input):
            if user_input in self.used_idioms:
                used_idiom_dialogues = [
                    "这个成语已经被使用过了，请换一个。",
                    "你刚才已经使用过这个成语了，请重新输入。",
                    "成语已被用过，请提供一个新的成语。",
                ]
                return random.choice(used_idiom_dialogues), self.current_idiom
            else:
                invalid_idiom_dialogues = [
                    "这不是一个有效的成语，请重新输入。",
                    "你说的不是成语哦，换一个吧。",
                    "这个好像不是成语，再想一个吧。",
                ]
                return random.choice(invalid_idiom_dialogues), self.current_idiom

        return self.process_user_idiom(user_input)
        

