class MultiTurnDialogue:
    def __init__(self):
        self.dialogue_history = []
        self.last_mentioned_topic = None
        self.topic_lifespans = {}
        self.keyword_weights = {}
        self.topics = topics  # 假设 topics 字典已在全局范围内定义

    def add_to_dialogue_history(self, user_input):
        """添加用户输入到对话历史，并保持历史记录在最近6条内"""
        self.dialogue_history.append(user_input.lower())
        if len(self.dialogue_history) > 6:
            self.dialogue_history.pop(0)

    def update_keyword_weights(self, topic, matched_keywords):
        """更新关键词权重"""
        for keyword in self.topics[topic]['keywords']:
            if keyword not in self.keyword_weights:
                self.keyword_weights[keyword] = 1
            else:
                self.keyword_weights[keyword] *= 0.9
        
        for keyword in matched_keywords:
            self.keyword_weights[keyword] = self.keyword_weights.get(keyword, 0) + 1

    def get_topic_score(self, topic, matched_keywords):
        """计算话题得分"""
        score = 0
        for keyword in matched_keywords:
            if keyword in self.topics[topic]['keywords']:
                score += self.keyword_weights.get(keyword, 1)
        return score

    def check_for_comforting(self):
        """检查是否需要给出安慰性回复"""
        combined_history = ' '.join(self.dialogue_history)
        matched_topics = []
        
        for topic, details in self.topics.items():
            matched_keywords = [keyword for keyword in details['keywords'] if keyword in combined_history]
            if len(matched_keywords) >= 3:  # 如果匹配到至少3个关键词
                matched_topics.append((topic, matched_keywords))
        
        if matched_topics:
            # 选择得分最高的话题
            matched_topics.sort(key=lambda x: self.get_topic_score(x[0], x[1]), reverse=True)
            selected_topic, matched_keywords = matched_topics[0]
            
            # 更新最后提到的话题和其生命周期
            self.last_mentioned_topic = selected_topic
            self.topic_lifespans[selected_topic] = 3
            
            # 更新关键词权重
            self.update_keyword_weights(selected_topic, matched_keywords)
            
            # 检查当前用户输入是否包含与选定话题相关的关键词
            current_input = self.dialogue_history[-1]
            current_input_keywords = [keyword for keyword in matched_keywords if keyword in current_input]
            
            if current_input_keywords:
                # 返回选定话题的随机回复
                return random.choice(self.topics[selected_topic]['responses'])
            else:
                return ""
    
        return ""
    
    
    def get_topic_memory(self):
        """获取最后提到的话题的记忶"""
        if self.last_mentioned_topic:
            topic_emotion = self.topics[self.last_mentioned_topic]['emotion']
            if topic_emotion == '开心':
                return f"此外，我们之前讨论的{self.last_mentioned_topic}真是让人开心！"
            elif topic_emotion == '生气':
                return f"此外，您之前提到的{self.last_mentioned_topic}确实令人生气。让我们尝试放松一下心情。"
            elif topic_emotion == '焦虑':
                return f"此外，您对{self.last_mentioned_topic}感到焦虑，我在这里听您说话。"
            elif topic_emotion == '兴奋':
                return f"此外，谈到{self.last_mentioned_topic}时您显得非常兴奋！"
            elif topic_emotion == '好奇':
                return f"此外，我们之前谈到的{self.last_mentioned_topic}确实很有趣，继续探索吧！"
            elif topic_emotion == '中立':
                return f"此外，我们之前聊到{self.last_mentioned_topic}，有什么新想法吗？"
            else:
                return f"此外，您之前提到您{self.last_mentioned_topic}让您感到很难过，我理解您的心情。"
        return ""
        

from dataclasses import dataclass, field
from typing import List, Dict, Optional


@dataclass
class Role:
    name: str
    prefixes: List[str]
    suffixes: List[str]
    prefix_chance: float
    suffix_chance: float
    activation_replies: List[str]
    keywords: List[str]
    emotional_responses: Dict[str, str]
    special_responses: Dict[str, List[str]] = field(default_factory=dict)
    infixes: List[str] = field(default_factory=list)
    infix_chance: float = 0.0
    special_reply_chance: float = 0.0
    special_replies: List[str] = field(default_factory=list)

    def get_prefix(self) -> str:
        return random.choice(self.prefixes) if random.random() < self.prefix_chance else ""

    def get_suffix(self) -> str:
        return random.choice(self.suffixes) if random.random() < self.suffix_chance else ""

    def get_activation_reply(self) -> str:
        return random.choice(self.activation_replies)

    def get_special_reply(self) -> Optional[str]:
        if self.special_responses and random.random() < self.special_reply_chance:
            question = random.choice(list(self.special_responses.keys()))
            return random.choice(self.special_responses[question])
        return None

    def get_emotional_response(self, emotion: str) -> Optional[str]:
        return self.emotional_responses.get(emotion, None)

    def get_infix(self) -> str:
        return random.choice(self.infixes) if self.infixes and random.random() < self.infix_chance else ""
        
