        if role_match_response:
            return role_match_response
            
        # 检查角色的特定领域回答能力
        special_response = self.role_play_handler.check_special_response(input_text)
        if special_response:
            return special_response
            
                 
        # 保存原始输入文本
        original_input = input_text

        # 处理用户输入，进行情绪检测
        self.emotion_handler.process_user_input(input_text)

