    def process_user_input(self, text):
        """处理用户输入，进行情绪检测"""
        detected_emotion = self._detect_emotion(text)
        if detected_emotion:
            self.user_mood = detected_emotion
            self.recent_emotions.append(detected_emotion)
            self._update_emotion_count()
        else:
            self.recent_emotions.append(None)
            self.user_mood = "开心"  # 如果没有检测到情绪，重置为开心

        return text  # 返回原始文本，不添加表情

    def _detect_emotion(self, text):
        for emotion, triggers in self.emotion_triggers.items():
            if any(trigger in text for trigger in triggers):
                return emotion
        return None

    def _update_emotion_count(self):
        self.emotion_count.clear()
        for emotion in self.recent_emotions:
            if emotion:
                self.emotion_count[emotion] = self.emotion_count.get(emotion, 0) + 1

    def get_dominant_emotion(self):
        for emotion, count in self.emotion_count.items():
            if count >= 3:
                return emotion
        return None

    def add_emotion_to_bot_response(self, text):
        """为机器人回复添加表情，但不影响原始回复内容"""
        if text is None or any(word in text for word in self.blacklist):
            return text

        # 随机选择使用机器人当前回复的内容或用户的上一句输入作为情绪基础
        base_mood = self.user_mood if random.choice([True, False]) else self._detect_emotion(text)
        if not base_mood:
            base_mood = "开心"  # 如果没有检测到情绪，默认使用"开心"

        emotion_emoji = ""
        scene_emoji = ""

        # 选择情绪表情
        if base_mood in self.emotions:
            emotion_emojis, probability = self.emotions[base_mood]
            if random.random() < probability:
                emotion_emoji = " " + random.choice(emotion_emojis)

        # 选择场景表情
        if not emotion_emoji or (emotion_emoji and random.random() < 0.5):  # 50%的概率添加场景表情
            for scene, emojis in self.scene_emotions.items():
                if scene in text and random.random() < self.scene_probability:
                    scene_emoji = " " + random.choice(emojis)
                    break

        # 将表情添加到原始文本的末尾
        return text + emotion_emoji + scene_emoji

