from datetime import datetime, timedelta
from threading import Timer

class ReminderBot:
    response_templates = [
        "好的，我会在{time}{unit}后提醒你{task}",
        "收到！{time}{unit}后提醒你{task}",
        "记得哦，{time}{unit}后提醒你{task}",
        "别担心，我会在{time}{unit}后提醒你{task}",
        "放心吧！{time}{unit}后提醒你{task}",
        "明白了，{time}{unit}后我会提醒你{task}",
        "没问题，{time}{unit}后我会提醒你{task}",
        "明白。{time}{unit}后我会提醒你{task}",
        "了解，{time}{unit}后我会准时提醒你{task}",
        "收到请求，{time}{unit}后我会提醒你{task}"
    ]

    sensitive_words = ["跳楼", "自杀", "杀人", "吸毒", "轻生", "结束生命", "伤害自己", "自残", "吃屎", "死", "去死"]


    daily_reminder_responses = {
        "22:00": [
            "已经22点了，注意休息，早点睡觉哦！",
            "现在已经很晚了，该准备休息啦，保持健康的作息！",
            "夜深了，别忘了早点睡觉，明天会更好！"
        ],
        "00:00": [
            "已经是凌晨了，别熬夜了，快点睡觉吧。",
            "零点到了，深夜别忘了放松心情，早点休息！",
            "午夜时分，赶紧去休息吧。"
        ],
        "12:00": [
            "中午到了，记得按时吃饭，照顾好自己！",
            "现在是中午了，你吃午饭了吗？",
            "12点了，别忘了享受一顿美味的午餐！"
        ]
    }

    def __init__(self, arithmetic_converter, type_like_human):
        self.reminders = []
        self.arithmetic_converter = arithmetic_converter
        self.type_like_human = type_like_human
        self.setup_daily_reminders()

    def setup_daily_reminders(self):
        """设置每天固定时间的提醒"""
        self.set_daily_reminder(22, 0, "22:00")
        self.set_daily_reminder(0, 0, "00:00")
        self.set_daily_reminder(12, 0, "12:00")

    def set_daily_reminder(self, hour, minute, time_key):
        """设置每日定时提醒"""
        now = datetime.now()
        reminder_time = datetime(now.year, now.month, now.day, hour, minute)

        if now > reminder_time:
            # 如果提醒时间已经过了，设置到第二天
            reminder_time += timedelta(days=1)

        delay = (reminder_time - now).total_seconds()
        Timer(delay, self.send_daily_reminder, args=[time_key]).start()

    def send_daily_reminder(self, time_key):
        """发送每日定时提醒"""
        response = random.choice(self.daily_reminder_responses[time_key])
        self.type_like_human(response)
        hour, minute = map(int, time_key.split(":"))
        # 设置下一次提醒
        self.set_daily_reminder(hour, minute, time_key)

    

    def extract_time_and_task(self, user_input):
        """提取时间和任务"""
        patterns = [
            r'提醒我\s*(\d+|[一二两三四五六七八九十百千万]+)\s*(秒|分钟|分)(?:钟)?\s*(?:后)?\s*(.*)',
            r'我\s*(\d+|[一二两三四五六七八九十百千万]+)\s*(秒|分钟|分)(?:钟)?\s*后要\s*(.*)',
            r'(\d+|[一二两三四五六七八九十百千万]+)\s*(秒|分钟|分)(?:钟)?后提醒我\s*(.*)'
        ]
        
        for pattern in patterns:
            match = re.search(pattern, user_input)
            if match:
                time_str = match.group(1)
                unit = match.group(2)
                task = match.group(3).strip()
                
                # 去除任务中的标点符号
                task = re.sub(r'[，。！？!?、]', '', task)
                
                # 使用 arithmetic_converter 转换中文数字
                time_digit = self.arithmetic_converter.convert_chinese_to_arabic(time_str)
                
                if unit.startswith("分"):
                    return time_digit * 60, "分钟", task
                else:
                    return time_digit, "秒", task
        
        return None, None, None

    def check_for_sensitive_words(self, task):
        """检查任务中是否包含敏感词汇"""
        for word in self.sensitive_words:
            if word in task:
                return True
        return False

    def set_reminder(self, delay, unit, task):
        """设置提醒"""
        is_sensitive = self.check_for_sensitive_words(task)
        
        if is_sensitive:
            # 立即进行劝导，无需设置延时提醒
            self.send_sensitivity_warning(task)
            return None
        else:
            # 正常情况下发送确认提醒消息
            response_template = random.choice(self.response_templates)
            response = response_template.format(time=delay // 60 if unit == "分钟" else delay, unit=unit, task=task)

            timer = Timer(delay, self.send_reminder, args=[task])
            timer.start()

            self.reminders.append((timer, task))
            return response

    def send_reminder(self, task):
        """发送提醒"""
        reminder_templates = [
            f"提醒一下，别忘了{task}哦。",
            f"时间到了！记得{task}。",
            f"你让我提醒的事情：{task}，该做了！",
            f"现在是时候{task}了，快去吧！",
            f"嘿，别忘了{task}！",
            f"提醒时间到！该{task}了哦。",
            f"时间过得真快，该{task}了！",
            f"现在提醒你：{task}！",
            f"别忘了你要{task}哦，已经到时间啦！",
            f"该提醒你了，记得{task}哦。"
        ]

        reminder_message = random.choice(reminder_templates)
        self.type_like_human(reminder_message)

        # 从 reminders 列表中移除已触发的提醒
        self.reminders = [(t, m) for t, m in self.reminders if m != task]

    def send_sensitivity_warning(self, task):
        """当检测到敏感词汇时，立即发送劝导信息"""
        sensitivity_templates = [
            f"我不能提醒你{task}，这是不对的。请一定要好好照顾自己，生命很珍贵。",
            f"关于{task}的事情，我不能进行这样的提醒。如果你有什么心事，可以和我倾诉。请不要冲动，好吗。",
            f"我知道你可能正经历困难，但希望你能寻求帮助，不要轻易放弃自己。",
            f"{task}是不对的，如果感到绝望，请找一个信任的人聊聊，千万不要自己默默承受。"
        ]
        warning_message = random.choice(sensitivity_templates)
        self.type_like_human(warning_message)

    def handle_input(self, user_input):
        """处理用户输入"""
        delay, unit, task = self.extract_time_and_task(user_input)
        if delay is not None and task:
            # 检查是否包含违禁词
            if self.check_for_sensitive_words(task):
                self.send_sensitivity_warning(task)
                return  # 直接返回，不再继续处理
            return self.set_reminder(delay, unit, task)
        return None

    def check_reminders(self):
        """检查是否有到期的提醒"""
        pass



